PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE templates (
    id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
    name TEXT NOT NULL DEFAULT 'Untitled Template',
    slug TEXT,
    thumbnail TEXT,
    category TEXT DEFAULT 'Wedding',
    zoom REAL DEFAULT 1,
    pan TEXT DEFAULT '{"x": 0, "y": 0}',
    sections TEXT DEFAULT '[]',
    layers TEXT DEFAULT '[]',
    created_at TEXT DEFAULT (datetime('now')),
    updated_at TEXT DEFAULT (datetime('now'))
, orbit TEXT DEFAULT '{}', type TEXT DEFAULT 'invitation', music TEXT, orbit_layers TEXT DEFAULT '[]');
CREATE TABLE invitations (
    id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
    user_id TEXT,
    template_id TEXT,
    name TEXT NOT NULL DEFAULT 'Untitled Invitation',
    slug TEXT UNIQUE,
    thumbnail_url TEXT,
    category TEXT DEFAULT 'Wedding',
    zoom REAL DEFAULT 1,
    pan TEXT DEFAULT '{"x": 0, "y": 0}',
    sections TEXT DEFAULT '[]',
    layers TEXT DEFAULT '[]',
    orbit TEXT DEFAULT '[]',
    is_published INTEGER DEFAULT 0,
    created_at TEXT DEFAULT (datetime('now')),
    updated_at TEXT DEFAULT (datetime('now')), music TEXT, display_design_id TEXT, orbit_layers TEXT DEFAULT '[]', event_date TEXT, event_location TEXT, venue_name TEXT, address TEXT, google_maps_url TEXT, seo_title TEXT, seo_description TEXT, og_image TEXT, gallery_photos TEXT DEFAULT '[]', livestream_url TEXT DEFAULT '', love_story TEXT DEFAULT '[]', quote_text TEXT DEFAULT '', quote_author TEXT DEFAULT '', lucky_draw_settings TEXT DEFAULT '{}', expires_at TEXT,
    FOREIGN KEY (template_id) REFERENCES templates(id)
);
CREATE TABLE rsvp_responses (
    id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
    invitation_id TEXT NOT NULL,
    name TEXT NOT NULL,
    email TEXT,
    phone TEXT,
    attendance TEXT NOT NULL CHECK (attendance IN ('attending', 'not_attending', 'maybe')),
    guest_count INTEGER DEFAULT 1,
    meal_preference TEXT,
    song_request TEXT,
    message TEXT,
    ip_address TEXT,
    user_agent TEXT,
    submitted_at TEXT DEFAULT (datetime('now')),
    is_approved INTEGER DEFAULT 1,
    is_visible INTEGER DEFAULT 1,
    flagged_as_spam INTEGER DEFAULT 0,
    deleted_at TEXT,
    FOREIGN KEY (invitation_id) REFERENCES invitations(id) ON DELETE CASCADE
);
CREATE TABLE users (
    id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
    email TEXT UNIQUE NOT NULL,
    name TEXT,
    avatar_url TEXT,
    provider TEXT DEFAULT 'email',
    created_at TEXT DEFAULT (datetime('now')),
    updated_at TEXT DEFAULT (datetime('now'))
, phone TEXT, gender TEXT CHECK (gender IN ('male', 'female', '')), birth_date TEXT, tamuu_id TEXT, tier TEXT DEFAULT 'free', max_invitations INTEGER DEFAULT 1, invitation_count INTEGER DEFAULT 0, expires_at TEXT, role TEXT DEFAULT 'user', permissions TEXT DEFAULT '[]', password TEXT, bank1_name TEXT, bank1_number TEXT, bank1_holder TEXT, bank2_name TEXT, bank2_number TEXT, bank2_holder TEXT, emoney_type TEXT, emoney_number TEXT, gift_address TEXT, gift_recipient TEXT, status TEXT DEFAULT 'active');
CREATE TABLE assets (
    id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
    user_id TEXT,
    invitation_id TEXT,
    filename TEXT NOT NULL,
    content_type TEXT,
    size INTEGER,
    r2_key TEXT NOT NULL,
    public_url TEXT,
    created_at TEXT DEFAULT (datetime('now')), template_id TEXT,
    FOREIGN KEY (user_id) REFERENCES users(id),
    FOREIGN KEY (invitation_id) REFERENCES invitations(id) ON DELETE SET NULL
);
CREATE TABLE d1_migrations(
		id         INTEGER PRIMARY KEY AUTOINCREMENT,
		name       TEXT UNIQUE,
		applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE TABLE guests (
    id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
    invitation_id TEXT NOT NULL,
    name TEXT NOT NULL,
    phone TEXT,
    address TEXT DEFAULT 'di tempat',
    table_number TEXT,
    tier TEXT CHECK (tier IN ('reguler', 'vip', 'vvip')) DEFAULT 'reguler',
    guest_count INTEGER DEFAULT 1,
    check_in_code TEXT,
    shared_at TEXT,
    checked_in_at TEXT,
    checked_out_at TEXT,
    created_at TEXT DEFAULT (datetime('now')), slug TEXT,
    FOREIGN KEY (invitation_id) REFERENCES invitations(id) ON DELETE CASCADE
);
CREATE TABLE music_library (
    id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
    title TEXT NOT NULL,
    artist TEXT,
    url TEXT NOT NULL,
    category TEXT,
    duration TEXT,
    is_premium INTEGER DEFAULT 0,
    created_at TEXT DEFAULT (datetime('now'))
, user_id TEXT, source_type TEXT DEFAULT 'library', external_id TEXT);
CREATE TABLE user_wishlist (
    id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
    user_id TEXT NOT NULL,
    template_id TEXT NOT NULL,
    created_at TEXT DEFAULT (datetime('now')),
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
    FOREIGN KEY (template_id) REFERENCES templates(id) ON DELETE CASCADE,
    UNIQUE(user_id, template_id) -- Prevent duplicate entries
);
CREATE TABLE template_categories (
    id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
    name TEXT NOT NULL UNIQUE,
    slug TEXT NOT NULL UNIQUE,
    icon TEXT DEFAULT '📁',
    color TEXT DEFAULT '#6366F1',
    display_order INTEGER DEFAULT 0,
    is_active INTEGER DEFAULT 1,
    created_at TEXT DEFAULT (datetime('now')),
    updated_at TEXT DEFAULT (datetime('now'))
);
ANALYZE sqlite_schema;
CREATE TABLE user_display_designs (id TEXT PRIMARY KEY, user_id TEXT, invitation_id TEXT, name TEXT NOT NULL DEFAULT 'Untitled Display', content TEXT DEFAULT '{}', thumbnail_url TEXT, source_template_id TEXT, created_at TEXT DEFAULT (datetime('now')), updated_at TEXT DEFAULT (datetime('now')));
CREATE TABLE IF NOT EXISTS "billing_transactions" (
    id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
    user_id TEXT NOT NULL,
    external_id TEXT UNIQUE NOT NULL,
    amount INTEGER NOT NULL,
    currency TEXT DEFAULT 'IDR',
    status TEXT NOT NULL CHECK (status IN ('PENDING', 'PAID', 'EXPIRED', 'FAILED', 'CANCELLED')),
    tier TEXT NOT NULL,
    payment_method TEXT,
    payment_channel TEXT,
    payment_url TEXT,
    paid_at TEXT,
    created_at TEXT DEFAULT (datetime('now')),
    updated_at TEXT DEFAULT (datetime('now')),
    FOREIGN KEY (user_id) REFERENCES users(id)
);
CREATE TABLE blog_posts (id TEXT PRIMARY KEY, slug TEXT UNIQUE NOT NULL, title TEXT NOT NULL, content TEXT NOT NULL, excerpt TEXT, featured_image TEXT, author_id TEXT, status TEXT DEFAULT 'draft', published_at DATETIME, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, view_count INTEGER DEFAULT 0, seo_title TEXT, seo_description TEXT, seo_keywords TEXT, author_email TEXT, category TEXT, image_meta TEXT, image_alt TEXT, approved_by TEXT, is_published INTEGER DEFAULT 0, is_featured INTEGER DEFAULT 0, tags TEXT);
CREATE TABLE blog_categories (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL UNIQUE,
    slug TEXT NOT NULL UNIQUE,
    count INTEGER DEFAULT 0,
    created_at TEXT DEFAULT (datetime('now'))
);
CREATE TABLE blog_daily_stats (date TEXT NOT NULL, post_id TEXT, views INTEGER DEFAULT 0, visitors INTEGER DEFAULT 0, reads INTEGER DEFAULT 0, PRIMARY KEY (date, post_id));
CREATE TABLE shop_category (
    id TEXT PRIMARY KEY,
    nama_kategori TEXT NOT NULL,
    slug_kategori TEXT NOT NULL UNIQUE,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE shop_merchants (
    id TEXT PRIMARY KEY,
    user_id TEXT NOT NULL,
    slug TEXT NOT NULL UNIQUE, 
    nama_toko TEXT NOT NULL,
    deskripsi TEXT, 
    deskripsi_panjang TEXT, 
    category_id TEXT NOT NULL,
    logo_url TEXT,
    banner_url TEXT,
    is_verified INTEGER DEFAULT 0, 
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, facebook TEXT, tiktok TEXT, website TEXT, kota TEXT, is_sponsored INTEGER DEFAULT 0, is_landing_featured INTEGER DEFAULT 0, kontak_utama TEXT DEFAULT 'whatsapp',
    FOREIGN KEY(category_id) REFERENCES shop_category(id)
);
CREATE TABLE shop_contacts (
    merchant_id TEXT PRIMARY KEY,
    alamat TEXT,
    kota TEXT,
    whatsapp TEXT,
    instagram TEXT,
    email TEXT,
    jam_operasional TEXT,
    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, facebook TEXT, tiktok TEXT, website TEXT, youtube TEXT, x_url TEXT, tokopedia_url TEXT, shopee_url TEXT, phone TEXT, google_maps_url TEXT,
    FOREIGN KEY(merchant_id) REFERENCES shop_merchants(id) ON DELETE CASCADE
);
CREATE TABLE shop_products (
    id TEXT PRIMARY KEY,
    merchant_id TEXT NOT NULL,
    nama_produk TEXT NOT NULL,
    deskripsi TEXT NOT NULL,
    harga_estimasi TEXT, 
    status TEXT DEFAULT 'DRAFT', 
    is_ad_sponsored INTEGER DEFAULT 0, 
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP, kategori_produk TEXT, kota TEXT, tiktok_url TEXT, youtube_url TEXT, x_url TEXT, website_url TEXT, tokopedia_url TEXT, shopee_url TEXT, is_admin_listing INTEGER DEFAULT 0, custom_store_name TEXT, is_approved INTEGER DEFAULT 1, rejection_reason TEXT, slug TEXT, alamat_lengkap TEXT, google_maps_url TEXT, is_special INTEGER DEFAULT 0, is_featured INTEGER DEFAULT 0, is_landing_featured INTEGER DEFAULT 0, whatsapp TEXT, phone TEXT, instagram TEXT, facebook TEXT, kontak_utama TEXT,
    FOREIGN KEY(merchant_id) REFERENCES shop_merchants(id) ON DELETE CASCADE
);
CREATE TABLE shop_product_images (
    id TEXT PRIMARY KEY,
    product_id TEXT NOT NULL,
    image_url TEXT NOT NULL,
    order_index INTEGER DEFAULT 0,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY(product_id) REFERENCES shop_products(id) ON DELETE CASCADE
);
CREATE TABLE shop_wishlist (
    id TEXT PRIMARY KEY,
    user_id TEXT NOT NULL,
    product_id TEXT NOT NULL,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    UNIQUE(user_id, product_id), 
    FOREIGN KEY(product_id) REFERENCES shop_products(id) ON DELETE CASCADE
);
CREATE TABLE shop_analytics (
    id TEXT PRIMARY KEY,
    merchant_id TEXT NOT NULL,
    action_type TEXT NOT NULL, 
    metadata TEXT, 
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY(merchant_id) REFERENCES shop_merchants(id) ON DELETE CASCADE
);
CREATE TABLE shop_carousel (id TEXT PRIMARY KEY, image_url TEXT NOT NULL, link_url TEXT, order_index INTEGER DEFAULT 0, is_active INTEGER DEFAULT 1, created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE notifications (id TEXT PRIMARY KEY, user_id TEXT NOT NULL, title TEXT NOT NULL, message TEXT NOT NULL, type TEXT DEFAULT 'info', is_read INTEGER DEFAULT 0, link TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE shop_reports (id TEXT PRIMARY KEY, product_id TEXT NOT NULL, reporter_id TEXT, category TEXT NOT NULL, reason TEXT, status TEXT DEFAULT 'PENDING', created_at DATETIME DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY(product_id) REFERENCES shop_products(id) ON DELETE CASCADE);
CREATE TABLE shop_ads (id TEXT PRIMARY KEY, image_url TEXT NOT NULL, link_url TEXT, title TEXT, position TEXT DEFAULT 'PRODUCT_DETAIL_SIDEBAR', is_active INTEGER DEFAULT 1, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, merchant_id TEXT, total_impressions INTEGER DEFAULT 0, total_clicks INTEGER DEFAULT 0, budget_remaining INTEGER DEFAULT 0, is_approved INTEGER DEFAULT 1);
CREATE TABLE feedback (id TEXT PRIMARY KEY, user_id TEXT NOT NULL, category TEXT NOT NULL, message TEXT NOT NULL, status TEXT DEFAULT 'pending', created_at DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE shop_product_reviews (
    id TEXT PRIMARY KEY,
    product_id TEXT NOT NULL,
    user_id TEXT NOT NULL,
    rating INTEGER NOT NULL CHECK (rating >= 1 AND rating <= 5),
    comment TEXT,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    UNIQUE(product_id, user_id),
    FOREIGN KEY (product_id) REFERENCES shop_products(id),
    FOREIGN KEY (user_id) REFERENCES users(id)
);
CREATE TABLE push_subscriptions (
    id TEXT PRIMARY KEY,
    user_id TEXT NOT NULL,
    endpoint TEXT NOT NULL UNIQUE,
    p256dh TEXT NOT NULL,
    auth TEXT NOT NULL,
    platform TEXT, 
    user_agent TEXT,
    is_active INTEGER DEFAULT 1,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE seo_templates (
    id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
    intent_type TEXT NOT NULL, 
    section TEXT NOT NULL, 
    content_template TEXT NOT NULL, 
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE seo_city_metadata (
    city_name TEXT PRIMARY KEY,
    province TEXT,
    local_fact TEXT, 
    is_active INTEGER DEFAULT 1
);
CREATE TABLE seo_permutation_cache (
    id TEXT PRIMARY KEY, 
    slug_path TEXT UNIQUE NOT NULL, 
    generated_title TEXT,
    generated_description TEXT,
    generated_h1 TEXT,
    generated_body_content TEXT,
    last_updated DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE blog_carousel (
    id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
    image_url TEXT NOT NULL,
    link_url TEXT, 
    title TEXT, 
    category_label TEXT, 
    order_index INTEGER DEFAULT 0,
    is_active INTEGER DEFAULT 1,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE invitations_carousel (
    id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
    image_url TEXT NOT NULL,
    link_url TEXT,
    order_index INTEGER DEFAULT 0,
    is_active INTEGER DEFAULT 1,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE shop_conversations (
    id TEXT PRIMARY KEY,
    user_id TEXT NOT NULL,
    merchant_id TEXT NOT NULL,
    last_message TEXT,
    last_sender_id TEXT,
    unread_count_user INTEGER DEFAULT 0,
    unread_count_vendor INTEGER DEFAULT 0,
    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY(user_id) REFERENCES users(id),
    FOREIGN KEY(merchant_id) REFERENCES shop_merchants(id)
);
CREATE TABLE shop_messages (
    id TEXT PRIMARY KEY,
    conversation_id TEXT NOT NULL,
    sender_id TEXT NOT NULL,
    content TEXT NOT NULL,
    type TEXT DEFAULT 'text', 
    read_at DATETIME, 
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY(conversation_id) REFERENCES shop_conversations(id)
);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_templates_slug ON templates(slug);
CREATE INDEX idx_templates_updated ON templates(updated_at DESC);
CREATE INDEX idx_invitations_slug ON invitations(slug);
CREATE INDEX idx_invitations_user ON invitations(user_id);
CREATE INDEX idx_invitations_updated ON invitations(updated_at DESC);
CREATE INDEX idx_rsvp_invitation ON rsvp_responses(invitation_id);
CREATE INDEX idx_rsvp_submitted ON rsvp_responses(submitted_at DESC);
CREATE INDEX idx_rsvp_attendance ON rsvp_responses(attendance);
CREATE INDEX idx_users_email ON users(email);
CREATE INDEX idx_assets_user ON assets(user_id);
CREATE INDEX idx_assets_invitation ON assets(invitation_id);
CREATE INDEX idx_templates_type ON templates(type);
CREATE UNIQUE INDEX idx_users_tamuu_id_unique ON users(tamuu_id);
CREATE INDEX idx_guests_invitation ON guests(invitation_id);
CREATE INDEX idx_guests_checkin ON guests(check_in_code);
CREATE INDEX idx_music_category ON music_library(category);
CREATE INDEX idx_music_user ON music_library(user_id);
CREATE INDEX idx_wishlist_user ON user_wishlist(user_id);
CREATE INDEX idx_wishlist_template ON user_wishlist(template_id);
CREATE INDEX idx_categories_order ON template_categories(display_order);
CREATE INDEX idx_invitations_event_date ON invitations(event_date);
CREATE INDEX idx_user_display_designs_user ON user_display_designs(user_id);
CREATE INDEX idx_user_display_designs_invitation ON user_display_designs(invitation_id);
CREATE INDEX idx_billing_user ON billing_transactions(user_id);
CREATE INDEX idx_billing_external ON billing_transactions(external_id);
CREATE INDEX idx_billing_status ON billing_transactions(status);
CREATE INDEX idx_blog_posts_slug ON blog_posts(slug);
CREATE INDEX idx_blog_posts_status ON blog_posts(status);
CREATE INDEX idx_blog_posts_category ON blog_posts(category);
CREATE INDEX idx_category_slug ON blog_categories(slug);
CREATE INDEX idx_blog_featured ON blog_posts(is_featured) WHERE is_featured = 1;
CREATE INDEX idx_shop_merchants_slug ON shop_merchants(slug);
CREATE INDEX idx_shop_merchants_user_id ON shop_merchants(user_id);
CREATE INDEX idx_shop_products_merchant ON shop_products(merchant_id);
CREATE INDEX idx_product_images_order ON shop_product_images(product_id, order_index);
CREATE INDEX idx_shop_analytics_merchant_action ON shop_analytics(merchant_id, action_type);
CREATE INDEX idx_notifications_user ON notifications(user_id);
CREATE INDEX idx_notifications_created ON notifications(created_at DESC);
CREATE UNIQUE INDEX idx_shop_products_merchant_slug ON shop_products(merchant_id, slug);
CREATE INDEX idx_shop_reports_product ON shop_reports(product_id);
CREATE INDEX idx_shop_reports_status ON shop_reports(status);
CREATE UNIQUE INDEX idx_guests_unique_token ON guests(check_in_code);
CREATE UNIQUE INDEX idx_guests_unique_slug_per_invitation ON guests(invitation_id, slug);
CREATE INDEX idx_guests_name ON guests(name);
CREATE INDEX idx_assets_template ON assets(template_id);
CREATE INDEX idx_push_user ON push_subscriptions(user_id);
CREATE INDEX idx_push_endpoint ON push_subscriptions(endpoint);
CREATE INDEX idx_push_active ON push_subscriptions(is_active);
CREATE INDEX idx_seo_intent ON seo_templates(intent_type);
CREATE INDEX idx_seo_cache_path ON seo_permutation_cache(slug_path);
CREATE INDEX idx_blog_carousel_active ON blog_carousel(is_active);
CREATE INDEX idx_blog_carousel_order ON blog_carousel(order_index);
CREATE INDEX idx_inv_car_active ON invitations_carousel(is_active);
CREATE INDEX idx_inv_car_order ON invitations_carousel(order_index);
CREATE INDEX idx_shop_msgs_conv ON shop_messages(conversation_id);
CREATE INDEX idx_shop_conv_user ON shop_conversations(user_id);
CREATE INDEX idx_shop_conv_vendor ON shop_conversations(merchant_id);
